module priority_encoder_4bit(
    input [3:0] in,   // 4-bit binary input.

    output [1:0] out  // 2-bit binary output.
);

wire reverse_priority = (in[3]) ? 2'b11 :
             (in[2]) ? 2'b10 :
             (in[1]) ? 2'b01 :
             (in[0]) ? 2'b00 : 2'b00;
assign out = reverse_priority;

endmodule
